############################################# ### Generated from PreTeXt source ### ### https://pretextbook.org ### ############################################# ## DBsubject() ## DBchapter() ## DBsection() ## Level() ## KEYWORDS() ## TitleText1() ## EditionText1() ## AuthorText1() ## Section1(not reported) ## Problem1(1.2.9.129) ## Author() ## Institution() ## Language(en-US)
DOCUMENT();
############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "contextCurrency.pl", "contextPercent.pl", "randomPerson.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $decimal = random(0.02,0.06,0.001); $name = randomPerson(); $profession = list_random( 'a radiography technician', 'a microelectronics engineer', 'a dental hygienist', 'a high school teacher', 'an office manager', 'a restaurant manager', 'a web designer', 'a tax accountant', 'a paralegal', 'a structural engineer' ); Context("Currency")->flags->set(trimTrailingZeros => 1, tolerance => 0.5); $final = 65000 + random(-8000,8000); $current = Currency($final); $solution = $final/(1 + $decimal); $before = Currency($solution); Context("Percent"); $percent = Percent($decimal);
############################################################ # Body ############################################################
BEGIN_PGML [$name]'s current annual salary as [$profession] is [`[$current]\text{.}`] This is with a raise of [`[$percent]`] over last year's salary. What was [$name->possessive] salary last year?
[_]{$before}{20}
END_PGML
############################################################ # End Problem ############################################################
ENDDOCUMENT();
